<?php
declare(strict_types=1);
if(preg_match('#^/booking/([a-f0-9]{64})$#',$path,$m)){$q=db()->prepare('SELECT b.*,m.name meeting_name,m.slug meeting_slug,m.duration_minutes,m.calendar_id,c.timezone calendar_timezone,c.external_provider_id,m.external_service_id FROM bookings b JOIN booking_meeting_types m ON m.id=b.meeting_type_id JOIN booking_calendars c ON c.id=b.calendar_id WHERE b.cancel_token=?');$q->execute([$m[1]]);$b=$q->fetch();if(!$b){http_response_code(404);exit('Booking not found');}if($method==='POST'){verify_csrf();$action=(string)post('action');if($action==='cancel'&&$b['status']==='confirmed'){if(ea_enabled()&&$b['external_appointment_id'])ea_cancel_appointment((int)$b['external_appointment_id']);db()->prepare("UPDATE bookings SET status='cancelled' WHERE id=?")->execute([$b['id']]);booking_send_confirmation((int)$b['id'],'cancelled');audit('cancel','booking',(int)$b['id']);flash('success','Your meeting was cancelled.');}elseif($action==='reschedule'&&$b['status']==='confirmed'){$slots=booking_slots($b);$selected=(string)post('starts_at');$start=null;foreach($slots as $slot)if(hash_equals($slot->format(DateTimeInterface::ATOM),$selected)){$start=$slot;break;}if(!$start)flash('error','That time is no longer available.');else{$end=$start->modify('+'.(int)$b['duration_minutes'].' minutes');if(ea_enabled())ea_reschedule_appointment((int)$b['external_appointment_id'],$start,$end);db()->prepare('UPDATE bookings SET starts_at=?,ends_at=? WHERE id=?')->execute([$start->format('Y-m-d H:i:s'),$end->format('Y-m-d H:i:s'),$b['id']]);db()->prepare("DELETE FROM booking_notification_log WHERE booking_id=? AND notification_type LIKE 'reminder_%'")->execute([$b['id']]);booking_schedule_reminders((int)$b['id']);booking_send_confirmation((int)$b['id'],'rescheduled');audit('reschedule','booking',(int)$b['id']);flash('success','Your meeting was rescheduled.');}}redirect('/booking/'.$m[1]);}$slots=$b['status']==='confirmed'?booking_slots($b,30):[];layout('Manage booking',function()use($b,$slots){?><div class="card login"><h1><?=e($b['meeting_name'])?></h1><p><strong>Status:</strong> <?=e(ucfirst($b['status']))?></p><p><?=e((new DateTimeImmutable($b['starts_at'],new DateTimeZone($b['timezone'])))->format('l, F j, Y \a\t g:i A T'))?></p><?php if($b['status']==='confirmed'):?><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><h2>Reschedule</h2><label>New time<select name="starts_at" required><?php foreach($slots as $slot):?><option value="<?=e($slot->format(DateTimeInterface::ATOM))?>"><?=e($slot->format('D, M j · g:i A'))?></option><?php endforeach?></select></label><button name="action" value="reschedule">Reschedule</button><button class="danger" name="action" value="cancel" formnovalidate onclick="return confirm('Cancel this meeting?')">Cancel meeting</button></form><?php endif?></div><?php });exit;}
if(preg_match('#^/bookings/types/(\d+)/questions$#',$path,$m)){require_permission('bookings.edit');$typeId=(int)$m[1];if($method==='POST'){verify_csrf();$action=(string)post('action');if($action==='add'){db()->prepare('INSERT INTO booking_questions(meeting_type_id,label,field_key,field_type,options_json,required,position) VALUES(?,?,?,?,?,?,?)')->execute([$typeId,trim((string)post('label')),preg_replace('/[^a-z0-9_]/','_',strtolower(trim((string)post('field_key')))),post('field_type'),json_encode(array_values(array_filter(array_map('trim',explode("\n",(string)post('options')))))),post('required')?1:0,(int)post('position')]);}elseif($action==='delete')db()->prepare('DELETE FROM booking_questions WHERE id=? AND meeting_type_id=?')->execute([(int)post('question_id'),$typeId]);audit($action,'booking_question');redirect('/bookings/types/'.$typeId.'/questions');}$t=db()->prepare('SELECT * FROM booking_meeting_types WHERE id=?');$t->execute([$typeId]);$type=$t->fetch();$q=db()->prepare('SELECT * FROM booking_questions WHERE meeting_type_id=? ORDER BY position,id');$q->execute([$typeId]);$rows=$q->fetchAll();layout('Booking questions',function()use($type,$rows){?><h1><?=e($type['name'])?> questions</h1><form class="card form-grid" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="add"><label>Question label<input name="label" required></label><label>Field key<input name="field_key" required></label><label>Type<select name="field_type"><option>text</option><option>textarea</option><option>select</option><option>checkbox</option></select></label><label>Options, one per line<textarea name="options"></textarea></label><label>Position<input type="number" name="position" value="10"></label><label><input type="checkbox" name="required" value="1" style="width:auto"> Required</label><button>Add question</button></form><div class="card"><table><?php foreach($rows as $r):?><tr><td><?=e($r['label'])?></td><td><?=e($r['field_type'])?></td><td><?=$r['required']?'Required':'Optional'?></td><td><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="question_id" value="<?=$r['id']?>"><button class="danger compact">Delete</button></form></td></tr><?php endforeach?></table></div><?php });exit;}
if(str_starts_with($path,'/booking/')||str_starts_with($path,'/bookings/types/'))return;
